SELECT up.upgrade, count(*) AS change FROM comstock_amy2018_r2_2025_md_agg_by_state_and_county_parquet AS up JOIN comstock_amy2018_r2_2025_md_agg_by_state_and_county_parquet AS bs ON bs.bldg_id = up.bldg_id AND bs.county = up.county AND bs.state = up.state AND bs.upgrade = 0 WHERE bs.applicability = true AND up.applicability = true AND up.upgrade != 0 AND (up."out.electricity.total.energy_consumption..kwh" IS NULL OR bs."out.electricity.total.energy_consumption..kwh" IS NULL) AND (up."out.natural_gas.total.energy_consumption..kwh" IS NULL OR bs."out.natural_gas.total.energy_consumption..kwh" IS NULL) AND (up."out.other_fuel.total.energy_consumption..kwh" IS NULL OR bs."out.other_fuel.total.energy_consumption..kwh" IS NULL) AND (up."out.district_cooling.total.energy_consumption..kwh" IS NULL OR bs."out.district_cooling.total.energy_consumption..kwh" IS NULL) AND (up."out.district_heating.total.energy_consumption..kwh" IS NULL OR bs."out.district_heating.total.energy_consumption..kwh" IS NULL) GROUP BY 1 ORDER BY 1